create procedure [dbo].[CREATE_ATA] @FromDate datetime, @ToDate datetime, @Tablename as varchar(50) output AS IF OBJECT_ID('dbo.ATA','U') IS NOT NULL DROP TABLE ATA CREATE TABLE ATA ([Original Customer GSTIN/UIN/Name] varchar(32) ,[Original Document Number] varchar(21) ,[Original Document date] datetime ,[Revised Customer GSTIN/UIN/Name] varchar(32) ,[Revised Document Number] varchar(21) ,[Revised Document date] datetime ,[Recipient State Code] varchar(2) ,[Total Invoice Value] decimal ,[Category] varchar(1) ,[HSN/SAC of Supply] varchar(16) ,[Total Taxable Value] decimal ,[IGST Rate] decimal ,[IGST Amount] decimal ,[CGST Rate] decimal ,[CGST Amount] decimal ,[SGST Rate] decimal ,[SGST Amount] decimal ,[CESS Rate] decimal ,[CESS Amount] decimal ) Set @Tablename='ATA' Select @Tablename